1	//! API key authentication for the Layer 1 gateway.
2	//!
3	//! Loads `api_keys.json` at startup. Each key has scoped permissions:
4	//! read-only, session-create, or full-access. All MCP, REST, and
5	//! WebSocket endpoints validate the `X-API-Key` header through this
6	//! module before any gRPC call is made.
7	
8	use serde::{Deserialize, Serialize};
9	use std::collections::HashMap;
10	use std::path::PathBuf;
11	use std::sync::Arc;
12	
13	/// Permissions scoped to an API key.
14	#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
15	#[serde(rename_all = "lowercase")]
16	pub enum KeyPermission {
17	    ReadOnly,
18	    SessionCreate,
19	    FullAccess,
20	}
21	
22	impl KeyPermission {
23	    /// Returns true if this permission allows creating sessions.
24	    pub fn can_create_session(&self) -> bool {
25	        matches!(
26	            self,
27	            KeyPermission::SessionCreate | KeyPermission::FullAccess
28	        )
29	    }
30	
31	    /// Returns true if this permission allows mutating state.
32	    pub fn can_write(&self) -> bool {
33	        matches!(
34	            self,
35	            KeyPermission::SessionCreate | KeyPermission::FullAccess
36	        )
37	    }
38	
39	    /// Returns true if this permission allows reading state.
40	    pub fn can_read(&self) -> bool {
41	        true // all permissions allow reading
42	    }
43	}
44	
45	/// A single API key entry.
46	#[derive(Debug, Clone, Serialize, Deserialize)]
47	pub struct ApiKeyEntry {
48	    pub key: String,
49	    pub name: String,
50	    pub permission: KeyPermission,
51	}
52	
53	/// The API key registry, loaded from disk at startup.
54	#[derive(Debug, Clone, Serialize, Deserialize)]
55	pub struct KeyRegistry {
56	    keys: HashMap<String, ApiKeyEntry>,
57	}
58	
59	impl KeyRegistry {
60	    /// Load keys from a JSON file on disk. Creates a default
61	    /// admin key if the file does not exist.
62	    pub fn load(path: Option<PathBuf>) -> Result<Self, AuthError> {
63	        let path = path.unwrap_or_else(|| {
64	            let home = dirs_next();
65	            home.join(".ans").join("api_keys.json")
66	        });
67	
68	        match std::fs::read_to_string(&path) {
69	            Ok(contents) => {
70	                let registry: KeyRegistry = serde_json::from_str(&contents)
71	                    .map_err(|e| AuthError::ParseError(e.to_string()))?;
72	                Ok(registry)
73	            }
74	            Err(e) if e.kind() == std::io::ErrorKind::NotFound => {
75	                // Bootstrap with a default admin key
76	                let default = ApiKeyEntry {
77	                    key: uuid::Uuid::new_v4().to_string(),
78	                    name: "default-admin".into(),
79	                    permission: KeyPermission::FullAccess,
80	                };
81	                tracing::warn!(
82	                    key = %default.key,
83	                    "No api_keys.json found — generated default admin key"
84	                );
85	                Ok(KeyRegistry {
86	                    keys: [("default".into(), default)].into(),
87	                })
88	            }
89	            Err(e) => Err(AuthError::IoError(e)),
90	        }
91	    }
92	
93	    /// Validate an API key and return its entry.
94	    pub fn validate(&self, api_key: &str) -> Option<&ApiKeyEntry> {
95	        self.keys.values().find(|entry| entry.key == api_key)
96	    }
97	}
98	
99	/// Cached in an Arc so all request handlers share the same registry.
100	pub type SharedKeyRegistry = Arc<KeyRegistry>;
101	
102	/// Errors that can occur during authentication.
103	#[derive(Debug, thiserror::Error)]
104	pub enum AuthError {
105	    #[error("missing API key")]
106	    MissingKey,
107	
108	    #[error("invalid API key")]
109	    InvalidKey,
110	
111	    #[error("insufficient permissions: required {required:?}, have {have:?}")]
112	    InsufficientPermissions {
113	        required: KeyPermission,
114	        have: KeyPermission,
115	    },
116	
117	    #[error("failed to parse api_keys.json: {0}")]
118	    ParseError(String),
119	
120	    #[error("io error: {0}")]
121	    IoError(#[from] std::io::Error),
122	}
123	
124	/// Extract an API key from an HTTP header or query parameter.
125	pub fn extract_api_key(headers: &axum::http::HeaderMap, query: Option<&str>) -> Option<String> {
126	    // Check X-API-Key header first
127	    if let Some(value) = headers.get("x-api-key") {
128	        return value.to_str().ok().map(String::from);
129	    }
130	    // Fall back to authorization bearer token
131	    if let Some(value) = headers.get("authorization") {
132	        if let Ok(auth) = value.to_str() {
133	            if let Some(key) = auth.strip_prefix("Bearer ") {
134	                return Some(key.to_string());
135	            }
136	        }
137	    }
138	    // Check query parameter
139	    if let Some(q) = query {
140	        for pair in q.split('&') {
141	            if let Some(value) = pair.strip_prefix("api_key=") {
142	                return Some(value.to_string());
143	            }
144	        }
145	    }
146	    None
147	}
148	
149	/// Axum extractor that validates API keys.
150	///
151	/// Usage: add `AuthLayer::new(registry)` to your axum router.
152	#[derive(Clone)]
153	pub struct AuthLayer {
154	    registry: SharedKeyRegistry,
155	}
156	
157	impl AuthLayer {
158	    pub fn new(registry: SharedKeyRegistry) -> Self {
159	        Self { registry }
160	    }
161	}
162	
163	impl<S> tower::Layer<S> for AuthLayer {
164	    type Service = AuthMiddleware<S>;
165	
166	    fn layer(&self, inner: S) -> Self::Service {
167	        AuthMiddleware {
168	            inner,
169	            registry: Arc::clone(&self.registry),
170	        }
171	    }
172	}
173	
174	/// Tower service that validates the API key before each request.
175	#[derive(Clone)]
176	pub struct AuthMiddleware<S> {
177	    inner: S,
178	    registry: SharedKeyRegistry,
179	}
180	
181	impl<S, B> tower::Service<axum::http::Request<B>> for AuthMiddleware<S>
182	where
183	    S: tower::Service<axum::http::Request<B>, Response = axum::response::Response>
184	        + Clone
185	        + Send
186	        + 'static,
187	    S::Future: Send + 'static,
188	    B: Send + 'static,
189	{
190	    type Response = S::Response;
191	    type Error = S::Error;
192	    type Future = futures_util::future::BoxFuture<'static, Result<Self::Response, Self::Error>>;
193	
194	    fn poll_ready(
195	        &mut self,
196	        cx: &mut std::task::Context<'_>,
197	    ) -> std::task::Poll<Result<(), Self::Error>> {
198	        self.inner.poll_ready(cx)
199	    }
200	
201	    fn call(&mut self, req: axum::http::Request<B>) -> Self::Future {
202	        let registry = Arc::clone(&self.registry);
203	        let inner = self.inner.clone();
204	        let mut inner = std::mem::replace(&mut self.inner, inner);
205	
206	        // Extract headers before the request is consumed
207	        let headers = req.headers().clone();
208	        let query = req.uri().query().map(String::from);
209	
210	        Box::pin(async move {
211	            let api_key = extract_api_key(&headers, query.as_deref());
212	            match api_key {
213	                Some(key) if registry.validate(&key).is_some() => {
214	                    // Valid key — pass through
215	                    inner.call(req).await
216	                }
217	                Some(_) => {
218	                    let response = axum::response::Response::builder()
219	                        .status(axum::http::StatusCode::UNAUTHORIZED)
220	                        .body(axum::body::Body::from(r#"{"error":"invalid API key"}"#))
221	                        .unwrap();
222	                    Ok(response)
223	                }
224	                None => {
225	                    let response = axum::response::Response::builder()
226	                        .status(axum::http::StatusCode::UNAUTHORIZED)
227	                        .body(axum::body::Body::from(
228	                            r#"{"error":"missing X-API-Key header"}"#,
229	                        ))
230	                        .unwrap();
231	                    Ok(response)
232	                }
233	            }
234	        })
235	    }
236	}
237	
238	/// Helper to get the user's home directory.
239	fn dirs_next() -> PathBuf {
240	    std::env::var("USERPROFILE")
241	        .or_else(|_| std::env::var("HOME"))
242	        .map(PathBuf::from)
243	        .unwrap_or_else(|_| PathBuf::from("."))
244	}
245	
246	#[cfg(test)]
247	mod tests {
248	    use super::*;
249	
250	    #[test]
251	    fn test_key_validation() {
252	        let registry = KeyRegistry {
253	            keys: [(
254	                "admin".into(),
255	                ApiKeyEntry {
256	                    key: "secret-123".into(),
257	                    name: "Test Admin".into(),
258	                    permission: KeyPermission::FullAccess,
259	                },
260	            )]
261	            .into(),
262	        };
263	
264	        assert!(registry.validate("secret-123").is_some());
265	        assert!(registry.validate("wrong-key").is_none());
266	    }
267	
268	    #[test]
269	    fn test_permission_checks() {
270	        assert!(KeyPermission::FullAccess.can_create_session());
271	        assert!(KeyPermission::SessionCreate.can_create_session());
272	        assert!(!KeyPermission::ReadOnly.can_create_session());
273	
274	        assert!(KeyPermission::FullAccess.can_write());
275	        assert!(KeyPermission::SessionCreate.can_write());
276	        assert!(!KeyPermission::ReadOnly.can_write());
277	
278	        assert!(KeyPermission::ReadOnly.can_read());
279	    }
280	
281	    #[test]
282	    fn test_extract_api_key_from_header() {
283	        use axum::http::{HeaderMap, HeaderValue};
284	        let mut headers = HeaderMap::new();
285	        headers.insert("x-api-key", HeaderValue::from_static("my-key"));
286	        assert_eq!(extract_api_key(&headers, None), Some("my-key".to_string()));
287	    }
288	}
