1	//! Agent Nervous System daemon entry point.
2	//!
3	//! Starts two servers:
4	//! - gRPC server on loopback:50051 (internal Python/TS clients)
5	//! - Gateway on loopback:50052 (external AI agents — MCP, REST, WS)
6	//!
7	//! Both run concurrently. Chromium instances are cleaned up on exit
8	//! via RAII drop guards. Ctrl+C triggers graceful shutdown.
9	
10	use std::net::{IpAddr, Ipv4Addr, SocketAddr};
11	use std::path::PathBuf;
12	
13	use ans_ipc::IpcServer;
14	use clap::Parser;
15	use tracing_subscriber::EnvFilter;
16	
17	#[derive(Parser)]
18	#[command(name = "ans-daemon", version, about = "Agent Nervous System daemon")]
19	struct Cli {
20	    /// gRPC port to bind on loopback
21	    #[arg(long, default_value = "50051")]
22	    grpc_port: u16,
23	
24	    /// Gateway port to bind on loopback
25	    #[arg(long, default_value = "50052")]
26	    gateway_port: u16,
27	
28	    /// Path to ans.toml configuration file
29	    #[arg(long, default_value = "ans.toml")]
30	    config: PathBuf,
31	}
32	
33	#[tokio::main]
34	async fn main() {
35	    color_eyre::install().expect("failed to install color-eyre panic handler");
36	
37	    let cli = Cli::parse();
38	
39	    tracing_subscriber::fmt()
40	        .with_env_filter(
41	            EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("ans=debug,info")),
42	        )
43	        .init();
44	
45	    tracing::info!(version = env!("CARGO_PKG_VERSION"), "ans-daemon starting");
46	
47	    if let Some(cfg) = load_config(&cli.config) {
48	        tracing::info!(?cfg, "Config loaded");
49	    } else {
50	        tracing::info!("No config file found, using defaults");
51	    }
52	
53	    // ── Start gRPC server in background ──────────────────────────────
54	    let server = IpcServer::new();
55	    let grpc_addr = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), cli.grpc_port);
56	
57	    let grpc_handle = tokio::spawn(async move {
58	        if let Err(e) = server.serve(grpc_addr).await {
59	            tracing::error!(%e, "gRPC server exited with error");
60	        }
61	    });
62	
63	    // Give the gRPC server a moment to bind before starting the gateway
64	    tokio::time::sleep(std::time::Duration::from_millis(300)).await;
65	
66	    // ── Start gateway ────────────────────────────────────────────────
67	    let gw_addr = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), cli.gateway_port);
68	
69	    let gw_handle = match ans_gateway::Gateway::init().await {
70	        Ok(gateway) => {
71	            tracing::info!("Gateway starting on {}", gw_addr);
72	            tokio::spawn(async move {
73	                if let Err(e) = gateway.serve(gw_addr).await {
74	                    tracing::error!(%e, "Gateway exited with error");
75	                }
76	            })
77	        }
78	        Err(e) => {
79	            tracing::warn!(%e, "Gateway failed to initialize — running gRPC-only");
80	            // Still wait for gRPC server
81	            let _ = grpc_handle.await;
82	            return;
83	        }
84	    };
85	
86	    // ── Wait for shutdown ────────────────────────────────────────────
87	    tokio::select! {
88	        _ = tokio::signal::ctrl_c() => {
89	            tracing::info!("Shutdown signal received");
90	        }
91	        _ = grpc_handle => {
92	            tracing::warn!("gRPC server exited unexpectedly");
93	        }
94	        _ = gw_handle => {
95	            tracing::warn!("Gateway exited unexpectedly");
96	        }
97	    }
98	
99	    tracing::info!("ans-daemon shut down cleanly");
100	}
101	
102	fn load_config(path: &PathBuf) -> Option<toml::Value> {
103	    let content = std::fs::read_to_string(path).ok()?;
104	    toml::from_str(&content).ok()
105	}
