99	fn detect_hidden_content(raw: &str) -> Vec<InjectionFlag> {
100	    let mut flags = Vec::new();
101	
102	    // display:none with substantial text content
103	    let display_none_re =
104	        regex::Regex::new(r#"(?is)style\s*=\s*"[^"]*display\s*:\s*none[^"]*"[^>]*>([^<]{20,})"#)
105	            .unwrap();
106	    for cap in display_none_re.captures_iter(raw) {
107	        let text = cap
108	            .get(1)
109	            .map(|m| m.as_str().trim().to_string())
110	            .unwrap_or_default();
111	        if contains_instruction_pattern(&text) {
112	            flags.push(InjectionFlag {
113	                content_snippet: text.chars().take(100).collect(),
114	                pattern_matched: "display:none with instruction content".into(),
115	                location: InjectionLocation::DisplayNone,
116	                confidence: 0.85,
117	            });
118	        }
119	    }
120	
121	    // visibility:hidden / opacity:0 with text
122	    let hidden_re = regex::Regex::new(
123	        r#"(?is)style\s*=\s*"[^"]*(?:visibility\s*:\s*hidden|opacity\s*:\s*0)[^"]*"[^>]*>([^<]{20,})"#,
124	    )
125	    .unwrap();
126	    for cap in hidden_re.captures_iter(raw) {
127	        let text = cap
128	            .get(1)
129	            .map(|m| m.as_str().trim().to_string())
130	            .unwrap_or_default();
131	        if contains_instruction_pattern(&text) {
132	            flags.push(InjectionFlag {
133	                content_snippet: text.chars().take(100).collect(),
134	                pattern_matched: "hidden element with instruction content".into(),
135	                location: InjectionLocation::HiddenDiv,
136	                confidence: 0.8,
137	            });
138	        }
139	    }
140	
141	    // aria-label with instruction-like content
142	    let aria_re = regex::Regex::new(r#"(?is)aria-label\s*=\s*"([^"]{30,})""#).unwrap();
143	    for cap in aria_re.captures_iter(raw) {
144	        let text = cap
145	            .get(1)
146	            .map(|m| m.as_str().to_string())
147	            .unwrap_or_default();
148	        if contains_instruction_pattern(&text) {
149	            flags.push(InjectionFlag {
150	                content_snippet: text.chars().take(100).collect(),
151	                pattern_matched: "aria-label with instruction content".into(),
152	                location: InjectionLocation::AriaLabel,
153	                confidence: 0.75,
154	            });
155	        }
156	    }
157	
158	    flags
159	}

1	//! Layer 1 External API Gateway.
2	//!
3	//! How external AI agents connect to the Agent Nervous System.
4	//! Three protocols, one gateway:
5	//!
6	//! - **MCP server** (Model Context Protocol): JSON-RPC tool provider
7	//!   for Claude, ChatGPT, and other MCP-compatible agents.
8	//! - **REST API**: Simple HTTP endpoints for non-MCP agents.
9	//! - **WebSocket**: Streaming events for real-time agent feedback.
10	//!
11	//! All connections are authenticated (API key), rate-limited, and
12	//! budget-tracked before any internal gRPC call is made.
