47	/// A parsed CDP response.
48	#[derive(Debug, Clone)]
49	pub struct CdpResponse {
50	    pub id: i64,
51	    pub result: Option<Json>,
52	    pub error: Option<CdpError>,
53	}
54	
55	impl CdpResponse {
56	    /// Extract `result` or return the CDP error.
57	    pub fn into_result(self) -> Result<Json, CdpError> {
58	        match self.result {
59	            Some(r) => Ok(r),
60	            None => Err(self.error.unwrap_or_else(|| CdpError {
61	                code: -1,
62	                message: "empty response".into(),
63	            })),
64	        }
65	    }
66	}
