68	#[derive(Debug, Clone)]
69	pub struct CdpError {
70	    pub code: i64,
71	    pub message: String,
72	}
73	
74	impl std::fmt::Display for CdpError {
75	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
