89	/// Inbound CDP message.
90	#[derive(Debug, Clone)]
91	pub enum CdpMessage {
92	    Response(CdpResponse),
93	    Event(CdpEvent),
94	}
95	
96	/// Parse a raw JSON-RPC message from the WebSocket into a [`CdpMessage`].
97	pub fn parse_message(text: &str) -> Option<CdpMessage> {
98	    let val: Json = serde_json::from_str(text).ok()?;
99	    let obj = val.as_object()?;
100	
101	    if let Some(id) = obj.get("id").and_then(|v| v.as_i64()) {
102	        let result = obj.get("result").cloned();
103	        let error = obj.get("error").map(|e| CdpError {
104	            code: e.get("code").and_then(|v| v.as_i64()).unwrap_or(-1),
105	            message: e
106	                .get("message")
107	                .and_then(|v| v.as_str())
108	                .unwrap_or("unknown")
109	                .to_string(),
110	        });
111	        return Some(CdpMessage::Response(CdpResponse { id, result, error }));
112	    }
113	
114	    if let Some(method) = obj.get("method").and_then(|v| v.as_str()) {
115	        let params = obj.get("params").cloned().unwrap_or(Json::Null);
116	        return Some(CdpMessage::Event(CdpEvent {
117	            method: method.to_string(),
118	            params,
119	        }));
120	    }
121	
122	    None
123	}
