352	// ── Simple base64 decoder (no external crate needed) ─────────────────
353	
354	fn base64_decode(input: &str) -> Option<Vec<u8>> {
355	    const CHARS: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
356	    let mut buf = Vec::with_capacity(input.len() * 3 / 4);
357	    let mut accum = 0u32;
358	    let mut bits = 0u32;
359	
360	    for b in input.bytes() {
361	        if b == b'=' {
362	            break;
363	        }
364	        if b.is_ascii_whitespace() {
365	            continue;
366	        }
367	        let idx = CHARS.iter().position(|&c| c == b)? as u32;
368	        accum = (accum << 6) | idx;
369	        bits += 6;
370	        if bits >= 8 {
371	            bits -= 8;
372	            buf.push((accum >> bits) as u8);
373	            accum &= (1 << bits) - 1;
374	        }
375	    }
376	    Some(buf)
377	}
